class Solution:
    def maximumSumOfHeights(self, maxHeights: List[int]) -> int:
        n = len(maxHeights)
        max_sum = 0

        # Try each index as the peak of the mountain
        for peak in range(n):
            heights = [0] * n
            # Set the peak to the maximum allowed value
            heights[peak] = maxHeights[peak]

            # Build increasing sequence to the left of the peak
            for i in range(peak - 1, -1, -1):
                heights[i] = min(maxHeights[i], heights[i + 1])

            # Build decreasing sequence to the right of the peak
            for i in range(peak + 1, n):
                heights[i] = min(maxHeights[i], heights[i - 1])

            # Check if the configuration is a mountain
            is_mountain = True
            # Check non-decreasing part (from start to peak)
            for i in range(1, peak + 1):
                if heights[i] < heights[i - 1]:
                    is_mountain = False
                    break
            # Check non-increasing part (from peak to end)
            for i in range(peak, n - 1):
                if heights[i + 1] > heights[i]:
                    is_mountain = False
                    break

            if is_mountain:
                max_sum = max(max_sum, sum(heights))

        return max_sum
